-- Setup table
CREATE TABLE jobs (
    id          UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    payload     JSONB NOT NULL,
    status      TEXT NOT NULL DEFAULT 'pending',
    attempts    INT  NOT NULL DEFAULT 0,
    created_at  TIMESTAMPTZ DEFAULT NOW(),
    scheduled_at TIMESTAMPTZ DEFAULT NOW()
);

-- Partial index — chỉ index pending jobs
CREATE INDEX idx_jobs_pending ON jobs(scheduled_at)
WHERE status = 'pending';

-- Worker query — lấy batch và skip locked rows
BEGIN;

SELECT id, payload
FROM jobs
WHERE status = 'pending'
  AND scheduled_at <= NOW()
ORDER BY scheduled_at
LIMIT 10
FOR UPDATE SKIP LOCKED;  -- ← magic: không đợi, bỏ qua

-- Cập nhật status ngay trong cùng transaction
UPDATE jobs
SET status = 'processing', attempts = attempts + 1
WHERE id = ANY(ARRAY[...ids từ SELECT...]);

COMMIT;
```

```csharp
// .NET implementation với Npgsql
public async Task<List<Job>> DequeueAsync(int batchSize, CancellationToken ct)
{
    await using var tx = await _conn.BeginTransactionAsync(ct);

    var jobs = await _conn.QueryAsync<Job>(
        """SELECT id, payload FROM jobs
           WHERE status = 'pending' AND scheduled_at <= NOW()
           ORDER BY scheduled_at LIMIT @batch
           FOR UPDATE SKIP LOCKED""",
        new { batch = batchSize });

    var ids = jobs.Select(j => j.Id).ToArray();
    if (ids.Length > 0)
        await _conn.ExecuteAsync(
            "UPDATE jobs SET status='processing' WHERE id = ANY(@ids)",
            new { ids });

    await tx.CommitAsync(ct);
    return jobs.ToList();
}
